import React from 'react';
import { Link } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';
import 'bootstrap/dist/js/bootstrap.bundle.min.js'; // Import Bootstrap JS for Offcanvas

const Header = ({ buttons }) => {
  return (
    <>
      {/* Navbar for larger screens */}
      <nav className="navbar navbar-expand-lg navbar-light bg-light">
        <a className="navbar-brand" href="#">
          <i className="fas fa-user-secret" style={{ fontSize: '30px' }}></i> {/* Font Awesome icon */}
          Personal
        </a>
        <button className="navbar-toggler d-md-none" type="button" data-bs-toggle="offcanvas" data-bs-target="#offcanvasNavbar" aria-controls="offcanvasNavbar" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse d-none d-md-block" id="navbarNav">
          <ul className="navbar-nav ml-auto">
            {buttons.map((button, index) => (
              <li className="nav-item" key={index}>
                <Link className="nav-link" to={button.to}>{button.text}</Link>
              </li>
            ))}
          </ul>
        </div>
      </nav>

      {/* Offcanvas Sidebar for smaller screens */}
      <div className="offcanvas offcanvas-start" tabIndex="-1" id="offcanvasNavbar" aria-labelledby="offcanvasNavbarLabel">
        <div className="offcanvas-header">
          <h5 id="offcanvasNavbarLabel">Menu</h5>
          <button type="button" className="btn-close" data-bs-dismiss="offcanvas" aria-label="Close"></button>
        </div>
        <div className="offcanvas-body">
          <ul className="navbar-nav">
            {buttons.map((button, index) => (
              <li className="nav-item" key={index}>
                <Link className="nav-link" to={button.to}>{button.text}</Link>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </>
  );
}

export default Header;
